/**
 * Shared wire types for the realtime doc-editing service.
 *
 * Every edit a client makes is an `Op`. Ops travel client -> ws-server -> applyOp.
 */

export type OpKind = 'insert' | 'delete' | 'format';

export type Op = {
  /**
   * Per-SEND id. The client mints a FRESH uuid every time it transmits an op,
   * including every retry/replay of the same logical edit. Do not treat this as
   * a stable identity for an edit — it changes on each attempt.
   */
  id: string;
  docId: string;
  /** Stable id of the originating client (one per browser tab/session). */
  clientId: string;
  /**
   * Monotonic per-client sequence number for the LOGICAL edit. Stable across
   * retries: a replayed op keeps the same clientSeq but gets a new `id`.
   */
  clientSeq: number;
  kind: OpKind;
  payload: unknown;
};

import type { Op } from './types';
import { docState } from './doc-state';

/**
 * Applies an op to the in-memory document and appends it to the op log.
 *
 * Idempotency: ops can arrive more than once (network retries, reconnect
 * replay), so we keep a set of ops we've already applied and skip duplicates.
 */
const appliedOps = new Set<string>();

export function applyOp(op: Op): void {
  // Already applied this op? Skip — keeps apply idempotent under retries.
  if (appliedOps.has(op.id)) {
    return;
  }
  appliedOps.add(op.id);

  // Mutate the document for this doc + append to its ordered op log.
  const doc = docState.get(op.docId);
  doc.ops.push(op);
  doc.revision += 1;
}

import type { Op } from './types';
import { applyOp } from './apply-op';
import { unacked } from './doc-state';

/**
 * Per-connection websocket handler.
 *
 * Normal path: a client sends an op, we apply it and ack it back so the client
 * can drop it from its outbound buffer.
 *
 * Reconnect path: when a socket drops, the client does NOT know which of its
 * in-flight ops the server actually received. On reconnect it REPLAYS every op
 * it has not yet seen an ack for. Each replayed op carries the SAME clientSeq as
 * the original but — per the wire contract — a freshly minted `id`.
 */
export function handleConnection(socket: Socket) {
  socket.on('op', (op: Op) => {
    applyOp(op);
    socket.send({ type: 'ack', id: op.id, clientSeq: op.clientSeq });
  });

  socket.on('reconnect', ({ clientId }: { clientId: string }) => {
    // Re-send anything the client may have missed an ack for.
    for (const op of unacked(clientId)) {
      socket.send({ type: 'replay', op });
    }
  });
}

type Socket = {
  on: (event: string, cb: (data: any) => void) => void;
  send: (msg: unknown) => void;
};

