export async function persistOp(db: Db, op: Op) {
  // Rely on the unique index to no-op on a duplicate replay.
  await db.query(
    `insert into ops (doc_id, client_id, client_seq, kind, payload)
     values ($1,$2,$3,$4,$5)
     on conflict (doc_id, client_id, client_seq) do nothing`,
    [op.docId, op.clientId, op.clientSeq, op.kind, op.payload],
  );
}
// the upsert keys ON CONFLICT by (doc_id, client_id, client_seq)

